import { mkdir, writeFile } from "node:fs/promises";
import path from "node:path";
import * as radix from "@radix-ui/colors";

const OUT_DIR = path.join("html", "vendor", "radix-colors-3.0.0", "scss");

const scales = [
  "amber",
  "blue",
  "cyan",
  "gray",
  "green",
  "indigo",
  "iris",
  "orange",
  "pink",
  "red",
  "teal",
  "yellow",
];

const header = `// Generated by scripts/generate-radix-scss.mjs from @radix-ui/colors.
// Do not edit this file directly.
`;

function scaleFor(name, mode) {
  const exportName = mode === "dark" ? `${name}Dark` : name;
  const scale = radix[exportName];

  if (!scale) {
    throw new Error(`Missing Radix color export: ${exportName}`);
  }

  return scale;
}

function scssVariableName(key) {
  return key.replace(/([a-z]+)(\d+)/, "$1-$2");
}

function render(mode) {
  const lines = [header.trimEnd(), ""];

  for (const name of scales) {
    const scale = scaleFor(name, mode);
    lines.push(`// ${name}`);

    for (const [key, value] of Object.entries(scale)) {
      lines.push(`$${scssVariableName(key)}: ${value};`);
    }

    lines.push("");
  }

  return `${lines.join("\n").trimEnd()}\n`;
}

await mkdir(OUT_DIR, { recursive: true });
await Promise.all([
  writeFile(path.join(OUT_DIR, "_light.scss"), render("light")),
  writeFile(path.join(OUT_DIR, "_dark.scss"), render("dark")),
]);
